    const responseBody = await response.text();

    const forwardedHeaders = {};
    const excludedHeaders = [
      'connection', 'keep-alive', 'proxy-authenticate', 'proxy-authorization',
      'te', 'trailer', 'transfer-encoding', 'upgrade',
      'content-encoding',
      'content-length',
      'set-cookie',
    ];

    response.headers.forEach((value, name) => {
      if (!excludedHeaders.includes(name.toLowerCase())) {
        forwardedHeaders[name] = value;
      }
    });

    forwardedHeaders['Access-Control-Allow-Origin'] = '*';
    forwardedHeaders['Access-Control-Allow-Methods'] = 'GET, POST, PUT, DELETE, OPTIONS';
    forwardedHeaders['Access-Control-Allow-Headers'] = 'Content-Type, Authorization';

